struct Tag {
	Tag(): add(0) {}
	Tag(int add): is_init(0), add(add) {}

	bool is_init = 1; // 初始化时不用 tag

	// 要维护的tag
	int add;
	void apply(const Tag& t) {
		// 父tag怎么传到子tag
		if (not t.is_init) {
			is_init = 0;
			add += t.add;
		}
	}
};
struct Info {
	Info() :mxcnt(0), mxid(0) {};
	Info(int pos) :mxcnt(0), mxid(pos) {};

	// 要维护的值
	int mxcnt, mxid; // 出现最多的出现的次数，出现最多的数(l == r 时，mxid = l)
	void apply(const Tag& t, int len) {
		// tag怎么传到要维护的值
		if (not t.is_init) {
			mxcnt += t.add;
		}
	}

	void apply(const Info& v) {
		// 如何单点修改
		mxid = v.mxid;
	}
};
Info operator+(const Info& a, const Info& b) {
	Info c;
	if (a.mxcnt > b.mxcnt) {
		c = a;
	}
	else if (b.mxcnt > a.mxcnt) {
		c = b;
	}
	else {
		// 次数相同，取编号小的
		c = a;
		c.mxid = min(a.mxid, b.mxid);
	}
	return c;
}

class ODT {
private:
	struct ODT_Node {
		int l, r;
		mutable int v; // 从 v 开始的等差数列

		// 重载小于号以用于 set 排序
		bool operator<(const ODT_Node& a)const {
			return l < a.l;
		}
	};

	// ODT 的核心操作：分裂区间
	// 将包含 pos 的区间 [l, r] 分裂为 [l, pos - 1] 和 [pos, r]
	// 返回指向后半段 [pos, r] 的迭代器
	auto split(int pos) {
		auto it = se.lower_bound({ pos, 0, 0 });
		if (it != se.end() and it->l == pos)return it;

		it = prev(it);
		auto [l, r, v] = *it;
		se.erase(it);
		se.insert({ l, pos - 1, v });

		// 核心修改：右半部分的起始值需要加上偏移量
		// 左边长度是 pos - 1 - l + 1 = pos - l
		// 所以右边从 v + (pos - l) 开始
		return se.insert({ pos, r, v + (pos - l)}).first;
	}

public:
	set<ODT_Node> se;


	// ODT 的核心操作：区间赋值（推平）
	void assign(LazySegmentTree<Info, Tag>& t, int l, int r, int d) {
		// 必须先 split 右边，再 split 左边，否则迭代器可能失效
		auto itr = split(r + 1);
		auto itl = split(l);

		// 遍历 [itl, itr) 之间的所有区间
		auto it = itl;
		while (it != itr) {
			auto [l, r, v] = *it;

			// 撤销旧区间的贡献
			// 旧区间包含的数值范围是 [v, v + (r - l)]
			t.modifyRange(v, v + (r - l), -1);

			// 删除旧区间，erase 返回下一个元素的迭代器
			it = se.erase(it);
		}

		// 插入新区间
		// 新区间数值范围 [d, d + (r - l)]
		se.insert({ l, r, d });
		t.modifyRange(d, d + (r - l), 1);
	}
};

void solve(int CASE)
{
	int n, m; cin >> n >> m;
	ODT odt;
	LazySegmentTree<Info, Tag> seg(2 * n + 1);
	fa(i, 1, 2 * n)seg.modify(i, i); // 值域初始化
	fa(i, 1, n) {
		int v; cin >> v;
		odt.se.insert({ i, i, v });
		seg.modifyRange(v, v, 1);
	}

	var res = seg.query(1, 2 * n);
	cout << res.mxid << " " << res.mxcnt << endl;
	while (m--) {
		int l, r, d; cin >> l >> r >> d;
		odt.assign(seg, l, r, d);
		res = seg.query(1, 2 * n);
		cout << res.mxid << " " << res.mxcnt << endl;
	}
	return;
}
